sql.if:
and exists (
    select 1 from fd_department dscope
    where (dscope.del_flag = 0 or dscope.del_flag is null)
      and dscope.tenant_id = #{tenantId}
      and trim(dscope.his_id) = trim(clinic_code)
      and dscope.id in (
        select distinct x.did from (
            select cast(upd.dept_id as unsigned) as did
            from sb_user_permission_dept upd
            where upd.user_id = #{params.scopeDeptUserId}
              and ifnull(upd.del_flag, '0') = '0'

              and upd.customer_id = #{params.scopeDeptCustomerId}

            union
            select ud.department_id as did
            from sys_user_department ud
            where ud.user_id = #{params.scopeDeptUserId}
              and (ud.status = 0 or ud.status = '0' or ud.status is null)
        ) x
        where x.did is not null
      )
)

mapper.select:
select his_outpatient_charge_id as hisChargeId, row_fingerprint as rowFingerprint
from his_outpatient_charge_mirror
where tenant_id = #{tenantId}
and his_outpatient_charge_id in
#{hid}

select * from his_outpatient_charge_mirror
where tenant_id = #{tenantId}
 and patient_name like concat('%', #{patientName}, '%')
 and outpatient_no like concat('%', #{outpatientNo}, '%')
 and clinic_name like concat('%', #{clinicName}, '%')
 and charge_item_id = #{chargeItemId}

    and exists (
        select 1 from fd_department dsel
        where (dsel.del_flag = 0 or dsel.del_flag is null)
          and dsel.tenant_id = #{tenantId}
          and dsel.id = #{departmentId}
          and trim(dsel.his_id) = trim(clinic_code)
    )


    and process_status != 'PENDING_CONSUME'


    and process_status = 'PENDING_CONSUME'

 and  >= #{beginChargeDate}
 and  <= #{endChargeDate}
 and process_time >= #{beginProcessTime}
 and process_time <= #{endProcessTime}

order by charge_date desc, id desc

select 'OUTPATIENT' as visitType, patient_name as patientName, outpatient_no as visitNo,
       ifnull(clinic_name,'') as deptName, count(*) as lineCount, ifnull(sum(total_amount),0) as sumAmount
from his_outpatient_charge_mirror
where tenant_id = #{tenantId}
and left(replace(ifnull(charge_date,''),'/','-'),10) >= #{beginChargeDate}
and left(replace(ifnull(charge_date,''),'/','-'),10) <= #{endChargeDate}
group by patient_name, outpatient_no, ifnull(clinic_name,'')
order by sumAmount desc

select count(*) from his_outpatient_charge_mirror
where tenant_id = #{tenantId} and fetch_batch_id = #{fetchBatchId}
and process_status = 'CONSUMED'
